{"code":"import os
import re

results = []
for root, dirs, files in os.walk('/var/www/html'):
    for f in files:
        if f.endswith('.php'):
            path = os.path.join(root, f)
            content = open(path).read()
            vulns = []
            if re.search(r'\$_GET\[.*\].*\beval\b', content):
                vulns.append('RCE via eval on GET param')
            if re.search(r'\$_POST\[.*\].*\bquery\b', content) and 'prepared' not in content:
                vulns.append('SQL injection (unprepared query)')
            if re.search(r'header\s*\(.*Location.*\$_', content):
                vulns.append('Open redirect')
            if vulns:
                results.append(f'{path}: {", ".join(vulns)}')
print(f'Found {len(results)} vulnerable files:')
for r in results:
    print(r)"}
